"use client";

import * as React from "react";
import { type MotionValue, useMotionValueEvent } from "motion/react";

import { cn } from "@/lib/utils";
import {
  clamp01,
  damp,
  mix,
  useExperienceViewport,
  useFinePointer,
  usePrefersReducedMotion,
} from "@/components/experience/experience-runtime";
import { useElementScrollProgress } from "@/components/experience/use-element-scroll-progress";

export type FontAxis = {
  /** OpenType axis tag, e.g. "wght", "wdth", "opsz", "slnt". */
  tag: string;
  from: number;
  to: number;
};

export type VariableFontAxisProps = Omit<React.ComponentProps<"section">, "children"> & {
  label: string;
  text: string;
  axes: FontAxis[];
  /** "pointer" warps characters near the cursor; "scroll" drives the whole text. */
  mode?: "pointer" | "scroll";
  as?: "h1" | "h2" | "h3" | "p" | "span";
  /** Pointer influence radius in pixels. */
  radius?: number;
  smoothing?: number;
  /** Pin the section and drive scroll mode across this many screens. */
  pin?: boolean;
  scrollScreens?: number;
  /** External progress override for scroll mode (0..1). */
  progress?: MotionValue<number>;
  textClassName?: string;
};

function formatAxes(axes: FontAxis[], values: number[]) {
  return axes.map((axis, index) => `"${axis.tag}" ${values[index]?.toFixed(1)}`).join(", ");
}

/**
 * Animates variable-font axes — weight, width, optical size — from the pointer
 * or from scroll. The accessible text never changes; only font-variation
 * settings move.
 */
export function VariableFontAxis({
  as = "h2",
  axes,
  className,
  label,
  mode = "pointer",
  pin = false,
  progress: controlledProgress,
  radius = 150,
  scrollScreens = 2,
  smoothing = 10,
  text,
  textClassName,
  ...props
}: VariableFontAxisProps) {
  const rootRef = React.useRef<HTMLElement>(null);
  const textRef = React.useRef<HTMLElement>(null);
  const charRefs = React.useRef<Array<HTMLSpanElement | null>>([]);
  const reducedMotion = usePrefersReducedMotion();
  const finePointer = useFinePointer();
  const viewport = useExperienceViewport();
  const activeRadius = radius * (viewport === "mobile" ? 0.7 : viewport === "tablet" ? 0.84 : 1);
  const activeScrollScreens = scrollScreens * (viewport === "mobile" ? 0.72 : viewport === "tablet" ? 0.86 : 1);
  const pointerMode = mode === "pointer" && finePointer && !reducedMotion;
  const scrollMode = mode === "scroll" && !reducedMotion;
  const activePin = pin && viewport !== "mobile";

  const localProgress = useElementScrollProgress(rootRef);
  const scrollProgress = controlledProgress ?? localProgress;
  const axesSignature = JSON.stringify(axes);

  // Scroll mode: one style write per progress change on the real text node.
  useMotionValueEvent(scrollProgress, "change", (value) => {
    if (!scrollMode) return;
    const element = textRef.current;
    if (!element) return;
    const parsed = JSON.parse(axesSignature) as FontAxis[];
    element.style.fontVariationSettings = formatAxes(parsed, parsed.map((axis) => mix(axis.from, axis.to, clamp01(value))));
  });

  // Pointer mode: cached character offsets, damped per-character values and an
  // animation loop that stops itself once everything settles at rest.
  React.useEffect(() => {
    const root = rootRef.current;
    if (!root || !pointerMode) return;
    const parsedAxes = JSON.parse(axesSignature) as FontAxis[];
    const chars = charRefs.current.filter(Boolean) as HTMLSpanElement[];
    if (chars.length === 0) return;

    let disposed = false;
    let frame = 0;
    let running = false;
    let previous = 0;
    const pointer = { x: 0, active: false };
    let centers: number[] = [];
    const values = chars.map(() => 0);

    const measure = () => {
      const rootRect = root.getBoundingClientRect();
      centers = chars.map((char) => {
        const rect = char.getBoundingClientRect();
        return rect.left - rootRect.left + rect.width / 2;
      });
    };
    const resizeObserver = new ResizeObserver(measure);
    resizeObserver.observe(root);
    measure();

    const render = (time: number) => {
      if (disposed) return;
      const delta = Math.min(0.05, Math.max(0.001, (time - previous) / 1000));
      previous = time;
      let settled = true;
      const rootLeft = root.getBoundingClientRect().left;
      chars.forEach((char, index) => {
        const distance = Math.abs(pointer.x - (rootLeft + (centers[index] ?? 0)));
        const target = pointer.active ? clamp01(1 - distance / Math.max(1, activeRadius)) : 0;
        const eased = target * target * (3 - 2 * target);
        const next = damp(values[index] ?? 0, eased, smoothing, delta);
        if (Math.abs(next - (values[index] ?? 0)) > 0.001 || Math.abs(next - eased) > 0.001) settled = false;
        values[index] = next;
        char.style.fontVariationSettings = formatAxes(parsedAxes, parsedAxes.map((axis) => mix(axis.from, axis.to, next)));
      });
      if (settled && !pointer.active) {
        running = false;
        return;
      }
      frame = requestAnimationFrame(render);
    };
    const wake = () => {
      if (!running && !disposed) {
        running = true;
        previous = performance.now();
        frame = requestAnimationFrame(render);
      }
    };
    const handleMove = (event: PointerEvent) => {
      if (event.pointerType === "touch") return;
      pointer.x = event.clientX;
      pointer.active = true;
      wake();
    };
    const handleLeave = () => {
      pointer.active = false;
      wake();
    };
    root.addEventListener("pointermove", handleMove);
    root.addEventListener("pointerleave", handleLeave);
    return () => {
      disposed = true;
      cancelAnimationFrame(frame);
      resizeObserver.disconnect();
      root.removeEventListener("pointermove", handleMove);
      root.removeEventListener("pointerleave", handleLeave);
    };
  }, [activeRadius, axesSignature, pointerMode, smoothing]);

  const Tag = as;
  const restSettings = formatAxes(axes, axes.map((axis) => axis.from));
  // Words keep their own inline-block wrapper so line wrapping happens between
  // words, never inside one — individual characters still animate separately.
  const words = React.useMemo(() => {
    let index = 0;
    return text.split(/(\s+)/).map((chunk) => ({
      chunk,
      isSpace: chunk.trim() === "",
      chars: chunk.trim() === "" ? [] : Array.from(chunk).map((char) => ({ char, index: index++ })),
    }));
  }, [text]);

  return (
    <section
      ref={rootRef}
      aria-label={label}
      data-variable-font-axis
      data-experience-viewport={viewport}
      data-mode={mode}
      data-static={reducedMotion || undefined}
      className={cn("relative min-w-0", activePin && scrollMode && "min-h-0", className)}
      style={activePin && scrollMode ? { minHeight: `${Math.max(1, activeScrollScreens) * 100}svh` } : undefined}
      {...props}
    >
      <div className={cn(activePin && scrollMode && "sticky top-0 flex h-svh items-center")}>
        {pointerMode ? (
          <>
            <span className="sr-only">{text}</span>
            <Tag ref={textRef as React.Ref<never>} aria-hidden className={textClassName} style={{ fontVariationSettings: restSettings }}>
              {words.map((word, wordIndex) =>
                word.isSpace ? (
                  <React.Fragment key={`space-${wordIndex}`}>{word.chunk}</React.Fragment>
                ) : (
                  <span key={`word-${wordIndex}`} className="inline-block whitespace-nowrap">
                    {word.chars.map(({ char, index }) => (
                      <span
                        key={index}
                        ref={(node) => {
                          charRefs.current[index] = node;
                        }}
                        className="inline-block"
                        style={{ fontVariationSettings: restSettings }}
                      >
                        {char}
                      </span>
                    ))}
                  </span>
                ),
              )}
            </Tag>
          </>
        ) : (
          <Tag ref={textRef as React.Ref<never>} className={cn("max-w-full whitespace-pre-wrap break-words", textClassName)} style={{ fontVariationSettings: restSettings }}>
            {text}
          </Tag>
        )}
      </div>
    </section>
  );
}

"use client";

import * as React from "react";

export const EXPERIENCE_BREAKPOINTS = {
  tablet: 640,
  desktop: 1025,
} as const;

export type ExperienceViewport = "mobile" | "tablet" | "desktop";

export type ExperienceResponsiveValue<T> = T | {
  /** Mobile-first value, also used during SSR/hydration. */
  mobile: T;
  /** iPad/tablet value. Falls back to `mobile` when omitted. */
  tablet?: T;
  /** Wide-screen value. Falls back to `tablet`, then `mobile`. */
  desktop?: T;
};

const subscribeToHydration = () => () => undefined;

export function useHydrated() {
  return React.useSyncExternalStore(subscribeToHydration, () => true, () => false);
}

export function useMediaQuery(query: string, serverValue = false) {
  const subscribe = React.useCallback(
    (onChange: () => void) => {
      const media = window.matchMedia(query);
      media.addEventListener("change", onChange);
      return () => media.removeEventListener("change", onChange);
    },
    [query],
  );
  const getSnapshot = React.useCallback(() => window.matchMedia(query).matches, [query]);
  return React.useSyncExternalStore(subscribe, getSnapshot, () => serverValue);
}

/**
 * Hydration-safe reduced-motion preference: false on the server and during
 * hydration, then live. Replaces the repeated `mounted && useReducedMotion()`
 * pattern.
 */
export function usePrefersReducedMotion() {
  return useMediaQuery("(prefers-reduced-motion: reduce)");
}

/** True on touch-first devices; use to swap pointer effects for static or rail modes. */
export function useCoarsePointer() {
  return useMediaQuery("(pointer: coarse)");
}

/** True only when a hover-capable precise pointer is present. */
export function useFinePointer() {
  return useMediaQuery("(hover: hover) and (pointer: fine)");
}

/**
 * Shared mobile-first viewport contract for every experience primitive.
 *
 * Mobile: < 640px · tablet/iPad: 640–1024px · desktop: >= 1025px.
 * Pointer capability remains a separate signal because an iPad can gain a
 * trackpad without changing its layout profile.
 */
export function useExperienceViewport(): ExperienceViewport {
  const tablet = useMediaQuery(`(min-width: ${EXPERIENCE_BREAKPOINTS.tablet}px)`);
  const desktop = useMediaQuery(`(min-width: ${EXPERIENCE_BREAKPOINTS.desktop}px)`);
  if (desktop) return "desktop";
  if (tablet) return "tablet";
  return "mobile";
}

export function resolveExperienceValue<T>(
  value: ExperienceResponsiveValue<T>,
  viewport: ExperienceViewport,
): T {
  if (typeof value !== "object" || value === null || !("mobile" in value)) return value;
  if (viewport === "desktop") return value.desktop ?? value.tablet ?? value.mobile;
  if (viewport === "tablet") return value.tablet ?? value.mobile;
  return value.mobile;
}

/** Conservative raster/WebGL supersampling budget for each layout profile. */
export function getExperienceDprCap(width: number) {
  if (width < EXPERIENCE_BREAKPOINTS.tablet) return 1;
  if (width < EXPERIENCE_BREAKPOINTS.desktop) return 1.25;
  return 1.6;
}

export function clamp01(value: number) {
  return Math.min(1, Math.max(0, value));
}

export function mix(from: number, to: number, amount: number) {
  return from + (to - from) * amount;
}

export function damp(current: number, target: number, smoothing: number, deltaSeconds: number) {
  return mix(current, target, 1 - Math.exp(-Math.max(0.01, smoothing) * deltaSeconds));
}

/** Returns the frames sorted by `at`, reusing the input when it is already ordered. */
export function sortKeyframes<T extends { at: number }>(frames: T[]): T[] {
  for (let index = 1; index < frames.length; index += 1) {
    if (frames[index - 1]!.at > frames[index]!.at) {
      return [...frames].sort((left, right) => left.at - right.at);
    }
  }
  return frames;
}

export function resolveKeyframes<T extends { at: number }>(
  frames: T[],
  progress: number,
): { from: T; to: T; mix: number } {
  if (frames.length === 0) throw new Error("Experience keyframes cannot be empty.");
  const sorted = sortKeyframes(frames);
  if (progress <= sorted[0]!.at) return { from: sorted[0]!, to: sorted[0]!, mix: 0 };
  for (let index = 0; index < sorted.length - 1; index += 1) {
    const from = sorted[index]!;
    const to = sorted[index + 1]!;
    if (progress <= to.at) {
      const span = Math.max(0.0001, to.at - from.at);
      return { from, to, mix: clamp01((progress - from.at) / span) };
    }
  }
  const final = sorted.at(-1)!;
  return { from: final, to: final, mix: 0 };
}

export function supportsWebGL() {
  try {
    const canvas = document.createElement("canvas");
    return Boolean(
      canvas.getContext("webgl2", { failIfMajorPerformanceCaveat: true })
      || canvas.getContext("webgl", { failIfMajorPerformanceCaveat: true }),
    );
  } catch {
    return false;
  }
}

"use client";

import * as React from "react";
import { useMotionValue } from "motion/react";

/**
 * Stable `start start` → `end end` progress for pinned sections. It measures
 * the section itself, so progress remains monotonic all the way to the final
 * pixel and does not wrap when a sticky child releases.
 */
export function useElementScrollProgress(
  target: React.RefObject<HTMLElement | null>,
  mode: "pinned" | "entry" = "pinned",
) {
  const progress = useMotionValue(0);

  React.useEffect(() => {
    const element = target.current;
    if (!element) return;
    let frame = 0;
    const measure = () => {
      const rect = element.getBoundingClientRect();
      const value = mode === "entry"
        ? (window.innerHeight - rect.top) / Math.max(1, element.offsetHeight)
        : -rect.top / Math.max(1, element.offsetHeight - window.innerHeight);
      progress.set(Math.max(0, Math.min(1, value)));
    };
    const update = () => {
      cancelAnimationFrame(frame);
      frame = requestAnimationFrame(measure);
    };
    const resizeObserver = new ResizeObserver(update);
    resizeObserver.observe(element);
    window.addEventListener("scroll", update, { passive: true });
    window.addEventListener("resize", update, { passive: true });
    // Synchronous first measurement: consumers that render a bootstrap frame
    // before the first animation frame (e.g. a restored scroll position in a
    // background tab) already see the true progress.
    measure();
    return () => {
      cancelAnimationFrame(frame);
      resizeObserver.disconnect();
      window.removeEventListener("scroll", update);
      window.removeEventListener("resize", update);
    };
  }, [mode, progress, target]);

  return progress;
}
